	idleCountVal, ok := esc["idle_count"].(float64)
	require.True(t, ok)
	assert.GreaterOrEqual(t, int(idleCountVal), preClaimIdleEscalationThreshold)

	assert.Contains(t, logBuf.String(), "operator attention: pre-claim idled")
